INSERT INTO system_edt_mappings (recid, element_name, element_mssql_type, element_postgresql_type, element_mysql_type, element_python_type, element_odbc_type_code, element_max_length, element_notes) VALUES (1, 'INT32', 'int', 'integer', 'int', 'int', 4, 4, 'Standard 32-bit signed integer.');
INSERT INTO system_edt_mappings (recid, element_name, element_mssql_type, element_postgresql_type, element_mysql_type, element_python_type, element_odbc_type_code, element_max_length, element_notes) VALUES (2, 'INT64', 'bigint', 'bigint', 'bigint', 'int', -5, 8, 'Standard 64-bit signed integer.');
INSERT INTO system_edt_mappings (recid, element_name, element_mssql_type, element_postgresql_type, element_mysql_type, element_python_type, element_odbc_type_code, element_max_length, element_notes) VALUES (3, 'INT64_IDENTITY', 'bigint identity(1,1)', 'bigserial', 'bigint auto_increment', 'int', -5, 8, 'Auto-numbering key: MSSQL IDENTITY, PostgreSQL BIGSERIAL, MySQL AUTO_INCREMENT.');
INSERT INTO system_edt_mappings (recid, element_name, element_mssql_type, element_postgresql_type, element_mysql_type, element_python_type, element_odbc_type_code, element_max_length, element_notes) VALUES (4, 'UUID', 'uniqueidentifier', 'uuid', 'char(36)', 'UUID', -11, 36, 'Prefer native UUID in MSSQL/PostgreSQL; MySQL commonly stores canonical text UUID unless BINARY(16) strategy is enabled.');
INSERT INTO system_edt_mappings (recid, element_name, element_mssql_type, element_postgresql_type, element_mysql_type, element_python_type, element_odbc_type_code, element_max_length, element_notes) VALUES (5, 'BOOL', 'bit', 'boolean', 'boolean', 'bool', -7, 1, 'MSSQL BIT stores 0/1; PostgreSQL and MySQL BOOLEAN are logical aliases.');
INSERT INTO system_edt_mappings (recid, element_name, element_mssql_type, element_postgresql_type, element_mysql_type, element_python_type, element_odbc_type_code, element_max_length, element_notes) VALUES (6, 'DATETIME', 'datetime2(7)', 'timestamp', 'datetime(6)', 'datetime', 93, NULL, 'Timezone-naive timestamp. MySQL DATETIME(6) stores no timezone metadata.');
INSERT INTO system_edt_mappings (recid, element_name, element_mssql_type, element_postgresql_type, element_mysql_type, element_python_type, element_odbc_type_code, element_max_length, element_notes) VALUES (7, 'DATETIME_TZ', 'datetimeoffset(7)', 'timestamptz', 'timestamp', 'datetime', -150, NULL, 'Timezone-aware moment. MSSQL datetimeoffset may surface as ODBC type -150 in metadata and requires explicit handling. MySQL TIMESTAMP normalizes to session/server timezone and has narrower range than MSSQL/PostgreSQL.');
INSERT INTO system_edt_mappings (recid, element_name, element_mssql_type, element_postgresql_type, element_mysql_type, element_python_type, element_odbc_type_code, element_max_length, element_notes) VALUES (8, 'STRING', 'nvarchar', 'varchar', 'varchar', 'str', -9, NULL, 'Bounded Unicode string. Use element_max_length for concrete column limits.');
INSERT INTO system_edt_mappings (recid, element_name, element_mssql_type, element_postgresql_type, element_mysql_type, element_python_type, element_odbc_type_code, element_max_length, element_notes) VALUES (9, 'TEXT', 'nvarchar(max)', 'text', 'longtext', 'str', -10, NULL, 'Large/unbounded text payload. Keep collation and indexing behavior provider-specific.');
