INSERT INTO system_schema_views (recid, element_name, element_schema, element_definition) VALUES (1, 'vw_account_user_sessions', 'dbo', 'CREATE VIEW [dbo].[vw_account_user_sessions] AS SELECT au.element_guid AS user_guid, ur.element_roles AS user_roles, au.element_created_on AS user_created_on, au.element_modified_on AS user_modified_on, au.element_rotkey, au.element_rotkey_iat, au.element_rotkey_exp, us.element_guid AS session_guid, us.element_created_on AS session_created_on, us.element_modified_on AS session_modified_on, sd.element_guid AS device_guid, sd.element_created_on AS device_created_on, sd.element_modified_on AS device_modified_on, sd.element_token, sd.element_token_iat, sd.element_token_exp, sd.element_revoked_at, sd.element_device_fingerprint, sd.element_user_agent, sd.element_ip_last_seen FROM dbo.account_users AS au JOIN dbo.users_sessions AS us ON au.element_guid = us.users_guid JOIN dbo.users_roles AS ur ON au.element_guid = ur.users_guid JOIN dbo.sessions_devices AS sd ON us.element_guid = sd.sessions_guid;');
INSERT INTO system_schema_views (recid, element_name, element_schema, element_definition) VALUES (2, 'vw_user_session_security', 'dbo', 'CREATE VIEW [dbo].[vw_user_session_security] AS SELECT au.element_guid AS user_guid, ur.element_roles AS user_roles, au.element_created_on AS user_created_on, au.element_modified_on AS user_modified_on, au.element_rotkey, au.element_rotkey_iat, au.element_rotkey_exp, us.element_guid AS session_guid, us.element_created_on AS session_created_on, us.element_modified_on AS session_modified_on, sd.element_guid AS device_guid, sd.element_created_on AS device_created_on, sd.element_modified_on AS device_modified_on, sd.element_token, sd.element_token_iat, sd.element_token_exp, sd.element_revoked_at, sd.element_device_fingerprint, sd.element_user_agent, sd.element_ip_last_seen FROM dbo.account_users AS au JOIN dbo.users_sessions AS us ON au.element_guid = us.users_guid JOIN dbo.users_roles AS ur ON au.element_guid = ur.users_guid JOIN dbo.sessions_devices AS sd ON us.element_guid = sd.sessions_guid;');
INSERT INTO system_schema_views (recid, element_name, element_schema, element_definition) VALUES (3, 'vw_account_user_security', 'dbo', 'CREATE VIEW [dbo].[vw_account_user_security] AS SELECT au.element_guid AS user_guid, au.element_rotkey, au.element_rotkey_iat, au.element_rotkey_exp, us.element_guid AS session_guid, sd.element_guid AS device_guid, sd.element_token, sd.element_token_iat, sd.element_token_exp, sd.element_revoked_at, sd.element_device_fingerprint, sd.element_user_agent, sd.element_ip_last_seen FROM dbo.account_users AS au JOIN dbo.users_sessions AS us ON au.element_guid = us.users_guid JOIN dbo.sessions_devices AS sd ON us.element_guid = sd.sessions_guid;');
INSERT INTO system_schema_views (recid, element_name, element_schema, element_definition) VALUES (4, 'vw_account_user_profile', 'dbo', 'CREATE VIEW [dbo].[vw_account_user_profile] AS SELECT au.element_guid AS user_guid, au.element_email AS email, au.element_display AS display_name, ap.element_name AS provider_name, ap.element_display AS provider_display, up.element_base64 AS profile_image_base64, au.element_optin AS opt_in, uc.element_credits AS credits FROM dbo.account_users AS au JOIN dbo.auth_providers AS ap ON au.providers_recid = ap.recid JOIN dbo.users_profileimg AS up ON au.element_guid = up.users_guid JOIN dbo.users_credits AS uc ON au.element_guid = uc.users_guid;');
INSERT INTO system_schema_views (recid, element_name, element_schema, element_definition) VALUES (5, 'vw_users_storage_cache', 'dbo', 'CREATE VIEW [dbo].[vw_users_storage_cache] AS SELECT [sc].[recid] ,[users_guid] ,[types_recid] ,[element_path] ,[element_filename] ,[element_public] ,[element_created_on] ,[element_modified_on] ,[element_deleted] ,[element_mimetype] ,[element_displaytype] FROM [dbo].[users_storage_cache] AS sc JOIN [dbo].[storage_types] AS st ON [types_recid] = [st].[recid];');
INSERT INTO system_schema_views (recid, element_name, element_schema, element_definition) VALUES (6, 'vw_conversation_history', 'dbo', 'CREATE VIEW vw_conversation_history AS SELECT ap.element_name AS persona_name ,am.element_name AS model_name ,ap.element_tokens AS element_token_allowance ,ac.[element_tokens] AS element_tokens_returned ,ac.[element_input] ,ac.[element_output] ,ac.[element_user_id] ,ac.[element_guild_id] ,ac.[element_channel_id] FROM [dbo].[assistant_conversations] ac JOIN [dbo].assistant_models am on am.recid = models_recid JOIN [dbo].assistant_personas ap on ap.recid = personas_recid;');
INSERT INTO system_schema_views (recid, element_name, element_schema, element_definition) VALUES (7, 'vw_personas', 'dbo', 'CREATE VIEW vw_personas AS SELECT ap.[element_name] AS persona_name ,am.[element_name] AS model_name ,ap.[element_tokens] AS token_allowance ,ap.[element_prompt] AS system_role_prompt ,ap.[element_created_on] ,ap.[element_modified_on] FROM [dbo].[assistant_personas] AS ap JOIN [dbo].[assistant_models] AS am ON am.recid = ap.models_recid;');
